import React from 'react';
import { NavLink, Outlet } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';

const links = [
  { to: '/account', end: true, label: 'Overview' },
  { to: '/account/orders', label: 'Orders' },
  { to: '/account/profile', label: 'Profile' },
  { to: '/account/addresses', label: 'Addresses' },
  { to: '/account/wishlist', label: 'Wishlist' }
];

export default function AccountLayout() {
  return (
    <>
      <Helmet>
        <title>My account | Nova Shop</title>
      </Helmet>
      <div className="container account-layout" style={{ padding: '2rem 1rem 4rem', display: 'grid', gap: '2rem' }}>
        <header className="page-header" style={{ marginBottom: 0 }}>
          <h1>My account</h1>
        </header>
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'minmax(180px, 220px) 1fr',
            gap: '2rem',
            alignItems: 'start'
          }}
          className="account-layout__grid"
        >
          <nav className="account-nav" aria-label="Account">
            <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
              {links.map(({ to, end, label }) => (
                <li key={to} style={{ marginBottom: '0.35rem' }}>
                  <NavLink
                    to={to}
                    end={end}
                    className={({ isActive }) =>
                      isActive ? 'btn btn-primary btn-sm btn-full' : 'btn btn-outline btn-sm btn-full'
                    }
                    style={{ justifyContent: 'center' }}
                  >
                    {label}
                  </NavLink>
                </li>
              ))}
            </ul>
          </nav>
          <div className="account-outlet">
            <Outlet />
          </div>
        </div>
      </div>
    </>
  );
}
